from pathlib import Path

path = Path(__file__).with_name('agent_live_windows_followup_apply.py')
content = path.read_text(encoding='utf-8')
old_helper = '''def remove_exact(content: str, value: str, label: str) -> str:\n    return replace_exact(content, value, "", label)\n'''
new_helper = '''def remove_exact(content: str, value: str, label: str) -> str:\n    count = content.count(value)\n    if count < 1:\n        raise RuntimeError(f"{label}: expected at least one exact match, found {count}")\n    return content.replace(value, "")\n'''
if content.count(old_helper) != 1:
    raise RuntimeError('remove_exact helper shape changed unexpectedly')
content = content.replace(old_helper, new_helper, 1)
duplicate = 'content = remove_exact(content, "  bestSafePositions: SoldierSafePosition[];\\n", "cached awareness safe positions")\n'
if content.count(duplicate) != 1:
    raise RuntimeError('duplicate cached safe-position removal step changed unexpectedly')
content = content.replace(duplicate, '', 1)
marker = '# Ensure the active source tree contains no safe-position feature identifiers.\n'
if content.count(marker) != 1:
    raise RuntimeError('final safe-position verification marker changed unexpectedly')
source_patch = '''# Remove the legacy safe-position field from the visual QA snapshot contract while retaining danger parity checks.\npath = "src/testing/CombatTacticalIntegrationVisualQaHarness.ts"\ncontent = read(path)\ncontent = remove_exact(content, "  readonly bestSafePosition: { x: number; y: number } | null;\\n", "visual QA safe-position snapshot field")\ncontent = remove_exact(\n    content,\n    "    bestSafePosition: report.bestSafePositions[0]\\n"\n    "      ? { ...report.bestSafePositions[0].position }\\n"\n    "      : null,\\n",\n    "visual QA safe-position snapshot value",\n)\nwrite(path, content)\n\n\n# Remove renderer-local safe-position fields from the movement harness.\npath = "src/testing/DangerLayerMovementPerformanceHarness.ts"\ncontent = read(path)\ncontent = remove_exact(content, "import type { SoldierSafePosition } from '../core/knowledge/SoldierAwarenessGrid';\\n", "movement harness safe-position import")\ncontent = remove_exact(content, "  readonly bestSafePosition: SoldierSafePosition | null;\\n", "movement harness safe-position field")\ncontent = remove_exact(content, "  readonly protectedAgainstThreatId: string | null;\\n", "movement harness protected threat field")\ncontent = remove_exact(content, "  readonly markerUpdateCount: number;\\n", "movement harness marker field")\ncontent = remove_exact(content, "  const winner = diagnostics?.rendererLocalBestWinner ?? null;\\n", "movement harness winner lookup")\ncontent = remove_exact(content, "    bestSafePosition: winner ? { ...winner, position: { ...winner.position } } : null,\\n", "movement harness winner snapshot")\ncontent = remove_exact(content, "    protectedAgainstThreatId: winner?.protectedAgainstThreatId ?? null,\\n", "movement harness protected threat snapshot")\ncontent = remove_exact(content, "    markerUpdateCount: diagnostics?.markerUpdateCount ?? 0,\\n", "movement harness marker snapshot")\nwrite(path, content)\n\n\n# Remove dead local safe-position timing diagnostics.\npath = "src/core/debug/AwarenessMovementDiagnostics.ts"\ncontent = read(path)\nfor line, label in [\n    ("  readonly ownMovementLocalUpdates: number;\\n", "own movement local diagnostics"),\n    ("  readonly safePositionLocalScans: number;\\n", "safe-position scan diagnostics"),\n    ("  readonly safePositionCellsScanned: number;\\n", "safe-position cells diagnostics"),\n    ("  readonly lastLocalUpdateMs: number;\\n", "last local update diagnostics"),\n    ("  /** Post-warmup maximum. The first local scan remains available as rawMaxLocalUpdateMs. */\\n", "local update comment"),\n    ("  readonly maxLocalUpdateMs: number;\\n", "max local update diagnostics"),\n    ("  readonly rawMaxLocalUpdateMs?: number;\\n", "raw local update diagnostics"),\n    ("  readonly localUpdateWarmupDiscarded?: number;\\n", "local warmup diagnostics"),\n    ("  readonly postWarmupLocalUpdateCount?: number;\\n", "local sample count diagnostics"),\n    ("  readonly postWarmupLocalUpdateP95Ms?: number;\\n", "local p95 diagnostics"),\n    ("  ownMovementLocalUpdates: 0,\\n", "empty own movement diagnostics"),\n    ("  safePositionLocalScans: 0,\\n", "empty safe-position scans"),\n    ("  safePositionCellsScanned: 0,\\n", "empty safe-position cells"),\n    ("  lastLocalUpdateMs: 0,\\n", "empty last local update"),\n    ("  maxLocalUpdateMs: 0,\\n", "empty max local update"),\n    ("  rawMaxLocalUpdateMs: 0,\\n", "empty raw local update"),\n    ("  localUpdateWarmupDiscarded: 0,\\n", "empty local warmup"),\n    ("  postWarmupLocalUpdateCount: 0,\\n", "empty local sample count"),\n    ("  postWarmupLocalUpdateP95Ms: 0,\\n", "empty local p95"),\n]:\n    content = remove_exact(content, line, label)\ncontent = replace_regex(\n    content,\n    r"\\nconst MAX_LOCAL_UPDATE_SAMPLES = 256;.*?\\nexport function getAwarenessMovementDiagnostics",\n    "\\nlet current: AwarenessMovementDiagnostics = EMPTY_DIAGNOSTICS;\\n\\nexport function publishAwarenessMovementDiagnostics(value: AwarenessMovementDiagnostics): void {\\n  current = { ...value };\\n}\\n\\nexport function getAwarenessMovementDiagnostics",\n    "local safe-position diagnostic aggregation",\n)\ncontent = replace_exact(\n    content,\n    "export function resetAwarenessMovementDiagnostics(): void {\\n"\n    "  current = EMPTY_DIAGNOSTICS;\\n"\n    "  lastObservedLocalUpdateCount = 0;\\n"\n    "  localWarmupDiscarded = false;\\n"\n    "  postWarmupLocalSamples = [];\\n"\n    "}\\n\\n"\n    "function percentile(values: readonly number[], fraction: number): number {\\n"\n    "  if (values.length === 0) return 0;\\n"\n    "  const sorted = [...values].sort((left, right) => left - right);\\n"\n    "  const index = Math.min(sorted.length - 1, Math.max(0, Math.ceil(sorted.length * fraction) - 1));\\n"\n    "  return sorted[index] ?? 0;\\n"\n    "}\\n",\n    "export function resetAwarenessMovementDiagnostics(): void {\\n  current = EMPTY_DIAGNOSTICS;\\n}\\n",\n    "local safe-position diagnostic reset",\n)\nwrite(path, content)\n\n\n# Remove matching zero-valued renderer diagnostics.\npath = "src/rendering/PixiAwarenessHeatmapRenderer.ts"\ncontent = read(path)\nfor line, label in [\n    ("    ownMovementLocalUpdates: 0,\\n", "renderer own movement diagnostics"),\n    ("    safePositionLocalScans: 0,\\n", "renderer safe-position scan diagnostics"),\n    ("    safePositionCellsScanned: 0,\\n", "renderer safe-position cells diagnostics"),\n    ("    lastLocalUpdateMs: 0,\\n", "renderer last local update diagnostics"),\n    ("    maxLocalUpdateMs: 0,\\n", "renderer max local update diagnostics"),\n]:\n    content = remove_exact(content, line, label)\nwrite(path, content)\n\n\n'''
content = content.replace(marker, source_patch + marker, 1)
path.write_text(content, encoding='utf-8')
print('Adjusted safe-position removal for runtime, harnesses, and diagnostics.')
